def binary_search(arr: List[Int], target: Int) -> Int:
    var lo = 0
    var hi = len(arr) - 1
    while lo <= hi:
        var mid = lo + (hi - lo) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

