    var c = List[List[Float64]]()
    for i in range(n):
        var row = List[Float64]()
        for j in range(m):
            var s: Float64 = 0.0
            for p in range(k):
                s += a[i][p] * b[p][j]
            row.append(s)
        c.append(row^)
    return c^

