    for cp_slice in s.codepoint_slices():
        if String(cp_slice) == " ":
            in_word = False
        else:
            if not in_word:
                count += 1
            in_word = True
    return count

def parse_int_checked(s: String) raises -> Int:
    if s.byte_length() == 0:
        raise Error("empty")
    var val = 0
    for cp in s.codepoints():
        var c = Int(cp)
        if c < 48 or c > 57:
