void selection_sort(std::vector<long>& v){
    long n = (long)v.size();
    for(long i=0;i<n-1;i++){
        long m=i;
        for(long j=i+1;j<n;j++) if(v[j]<v[m]) m=j;
        long t=v[i]; v[i]=v[m]; v[m]=t;
    }
}

