        int r = h[0];
        h[0] = h[h.size() - 1];
        h.pop_back();
        int i = 0; int n = (int)h.size();
        while (true) {
            int l = 2*i+1, ri = 2*i+2, s = i;
            if (l < n && h[l] < h[s]) s = l;
            if (ri < n && h[ri] < h[s]) s = ri;
            if (s == i) break;
            int t = h[s]; h[s] = h[i]; h[i] = t;
            i = s;
        }
        return r;
    }
