def count_substring_overlap(s: String, sub: String) -> Int:
    var n = s.byte_length()
    var m = sub.byte_length()
    if m == 0:
        return 0
    var count = 0
    for i in range(n - m + 1):
        var ok = 1
        for k in range(m):
            if String(s[byte=i + k]) != String(sub[byte=k]):
                ok = 0
                break
        if ok == 1:
            count += 1
    return count

def levenshtein(a: String, b: String) -> Int:
    var n = a.byte_length()
    var m = b.byte_length()
    var prev = List[Int]()
    var cur = List[Int]()
    for j in range(m + 1):
        prev.append(j)
        cur.append(0)
    for i in range(1, n + 1):
        cur[0] = i
        for j in range(1, m + 1):
            var cost = 1
            if String(a[byte=i - 1]) == String(b[byte=j - 1]):
                cost = 0
            var d = prev[j] + 1
            var ins = cur[j - 1] + 1
            var sb = prev[j - 1] + cost
            var mn = d
            if ins < mn:
                mn = ins
            if sb < mn:
                mn = sb
            cur[j] = mn
        for j in range(m + 1):
            prev[j] = cur[j]
    return prev[m]

