def gcd2(a_in: Int, b_in: Int) -> Int:
    var a = -a_in if a_in < 0 else a_in
    var b = -b_in if b_in < 0 else b_in
    while b != 0:
        var t = b
        b = a % b
        a = t
    return a

@fieldwise_init
