    var num: Int
    var den: Int

    def reduce(self) -> Frac2:
        var g = gcd2(self.num, self.den)
        if g == 0:
            return Frac2(self.num, self.den)
        return Frac2(self.num // g, self.den // g)

    def add(self, o: Frac2) -> Frac2:
        return Frac2(self.num * o.den + o.num * self.den, self.den * o.den).reduce()

