int lru_evict(const std::vector<int>& accesses, int cap, int query){
    std::map<int,int> present;
    std::vector<int> order;
    for (size_t i = 0; i < accesses.size(); ++i){
        int k = accesses[i];
        if (present.find(k) != present.end()){
            for (size_t j = 0; j < order.size(); ++j){ if (order[j] == k){ order.erase(order.begin()+j); break; } }
            order.push_back(k);
        } else {
            if ((int)order.size() >= cap){
                int victim = order.front();
                order.erase(order.begin());
                present.erase(victim);
            }
            present[k] = 1;
            order.push_back(k);
        }
    }
    return present.find(query) != present.end() ? 1 : 0;
}

