def lru_evict(accesses: List[Int], cap: Int, query: Int) raises -> Int:
    var present = Dict[Int, Int]()
    var order = List[Int]()
    for i in range(len(accesses)):
        var k = accesses[i]
        if k in present:
            for j in range(len(order)):
                if order[j] == k:
                    _ = order.pop(j)
                    break
            order.append(k)
        else:
            if len(order) >= cap:
                var victim = order[0]
                _ = order.pop(0)
                _ = present.pop(victim)
            present[k] = 1
            order.append(k)
    if query in present:
        return 1
    return 0

